code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let arr;
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
        arr = new Array(n);
        i++;
    } else {
        arr = line.split(' ').map(num => parseInt(num));
        for (let j = 1; j < n; j += 2) {
            process.stdout.write(arr[j] + ' ');
        }
        for (let j = 0; j < n; j += 2) {
            process.stdout.write(arr[j] + ' ');
        }
        readline.close();
    }
});

